    const oppNum = 'GA-' + Date.now() + '-' + Math.random().toString(36).substr(2, 5);
    let link = hrefMatch ? hrefMatch[1] : '';
    if (link && !link.startsWith('http')) {
      link = 'https://grantsmanagement.georgia.gov' + (link.startsWith('/') ? '' : '/') + link;
    }

    grants.push({
      json: {
        id: oppNum,
        oppNum: oppNum,
