await writeStatus('matching', 'Matching grants to your organization...');

const systemPrompt = `You are a grant relevance filter. You receive a search query, optional filters, and a list of grants. Your job is to decide which grants are genuinely relevant to the user's search.

FILTERING RULES:
1. Analyze the search query to understand the specific domain, topic, and intent.
2. Keep a grant ONLY if its Title or Description directly relates to the query's core topic.
3. Do NOT use loose semantic chains to justify keeping a grant.
4. Discard a grant if the connection to the search query requires more than one logical hop or is only tangential.
5. Ignore matches that only appear in the Funder Name, agency name, or as a generic geographic term.
6. When in doubt, DISCARD. Users prefer fewer, highly relevant results over many loosely related ones.

ADDITIONAL FILTERS (apply only if the value is provided and not "Any" or empty):
- Organization Type: Only keep grants whose eligible applicants include this org type.
- Nonprofit/For-Profit Status: If "Nonprofit", discard grants only for for-profits. If "For-Profit", discard grants only for nonprofits. If "Either" or empty, skip.
- Industry/Sector: Only keep grants relevant to this sector. Use semantic matching.
- Funding Category: "Federal Grant" = only federal. "Foundation / Private Grant" = only philanthropic/foundation. If empty, skip.
- Geographic Focus: If provided, only keep grants whose eligibility includes this geographic area.

Return ONLY a valid JSON object: {"ids": ["id1", "id2"], "no_results": false}
Or if none match: {"ids": [], "no_results": true}
No markdown. No explanation.`;

const allMatchedGrants = [];

for (let i = 0; i < newGrants.length; i += BATCH_SIZE) {
  const batch = newGrants.slice(i, i + BATCH_SIZE);

  const grantsToEvaluate = batch.map(item => {
    const g = item.json;
    return {
      id: g.oppNum || g.id || '',
      title: g.title || '',
      description: (g.description || '').substring(0, 500),
      agency: g.agency || ''
    };
  }).filter(g => g.title && g.id);

  if (grantsToEvaluate.length === 0) continue;

  await writeStatus('filtering', 'Filtering grants... (' + Math.min(i + BATCH_SIZE, newGrants.length) + '/' + newGrants.length + ')');

  try {
    const aiResponse = await $http.request({
      method: 'POST',
      url: 'https://api.openai.com/v1/responses',
      headers: {
        'Authorization': 'Bearer ' + openAiKey,
        'Content-Type': 'application/json',
      },
      body: {
        model: 'gpt-4.1-mini',
        input: [
          { role: 'system', content: systemPrompt },
          { role: 'user', content: 'Search Query: ' + searchQuery + '\n\nFilters:\n- Organization Type: ' + (webhookData.orgType || 'Any') + '\n- Nonprofit/For-Profit: ' + (webhookData.profitStatus || 'Any') + '\n- Industry/Sector: ' + (webhookData.industry || 'Any') + '\n- Funding Category: ' + (webhookData.fundingCategory || 'Any') + '\n\nGrants to evaluate:\n' + JSON.stringify(grantsToEvaluate, null, 2) }
        ]
      },
      timeout: 120000,
    });

    let keepIds = [];
    try {
      const text = aiResponse.output?.[0]?.content?.[0]?.text || '[]';
      const cleaned = text.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
      const parsed = JSON.parse(cleaned);
      keepIds = Array.isArray(parsed) ? parsed : (parsed.ids || []);
    } catch(e) {
      keepIds = [];
    }

    // Filter batch by AI results
    for (const item of batch) {
      const g = item.json;
      const grantId = String(g.oppNum || g.id || '');
      if (keepIds.includes(grantId)) {
        allMatchedGrants.push(g);
      }
    }

    // Write matched grants from this batch to Supabase immediately
    const batchMatches = [];
    for (const item of batch) {
      const g = item.json;
      const grantId = String(g.oppNum || g.id || '');
      if (keepIds.includes(grantId)) {
        batchMatches.push({ ...g, funder_name: g.agency || g.funder_name || 'Unknown' });
      }
    }

    if (batchMatches.length > 0) {
      await $http.request({
        method: 'POST',
        url: supabaseUrl + '/search_results',
        headers: supaHeaders,
        body: { search_id: searchId, org_id: orgId, source_group: 'ai_filtered_' + i, grant_data: batchMatches, is_complete: false },
      });
    }

  } catch(e) {
    // On AI error, skip batch
  }
}

if (allMatchedGrants.length === 0) {
  return [{ json: { noRelevantGrants: true, message: 'No grants matched your search filters', hasResults: false } }];
}

return allMatchedGrants.map(g => ({
  json: {
    grant: g,
    org_id: orgId,
    newGrants: true,
    status: 'new',
